241		// Worker B lives under the workers dir of the server's working directory
242		// (that is where GetWorkersGraphQL reads from) but targets project B via
243		// its ProjectRoot field — mirroring how ExecuteLoopWorkerSpec.ProjectRoot
244		// redirects a worker to another registered project.
245		writeWorkerRecord(t, workDirA, WorkerRecord{
246			ID:          "wk-scope-B",
247			Kind:        "execute-loop",
248			State:       "running",
249			ProjectRoot: workDirB,
250			Harness:     "claude",
251			StartedAt:   startedAt.Add(time.Minute),
252		})
253	
254		srv := New(":0", workDirA)
255		projA, ok := srv.state.GetProjectByPath(workDirA)
256		if !ok {
257			t.Fatalf("project A at %q not registered", workDirA)
258		}
259		projB := srv.state.RegisterProject(workDirB)
260	
261		if projA.ID == projB.ID {
262			t.Fatalf("expected distinct project ids, got %q", projA.ID)
263		}
264	
265		queryTotal := func(q string) int {
266			t.Helper()
267			body := gqlPost(t, srv, q)
268			if errs := gqlErrors(body); len(errs) > 0 {
269				t.Fatalf("GraphQL errors for %q: %v", q, errs)
270			}
271			var resp struct {
272				Data struct {
273					Workers struct {
274						TotalCount int `json:"totalCount"`
275						Edges      []struct {
276							Node struct {
277								ID string `json:"id"`
278							} `json:"node"`
279						} `json:"edges"`
280					} `json:"workersByProject,omitempty"`
281					Global struct {
282						TotalCount int `json:"totalCount"`
283						Edges      []struct {
284							Node struct {
285								ID string `json:"id"`
286							} `json:"node"`
287						} `json:"edges"`
288					} `json:"workers,omitempty"`
289				} `json:"data"`
290			}
291			if err := json.Unmarshal(body, &resp); err != nil {
292				t.Fatalf("invalid JSON for %q: %v", q, err)
293			}
294			return resp.Data.Workers.TotalCount + resp.Data.Global.TotalCount
295		}
296	
297		// workersByProject(projectID: projA.ID) must return exactly worker A.
298		workersForProject := func(id string) []string {
299			t.Helper()
300			q := fmt.Sprintf(`{ workersByProject(projectID: %q) { totalCount edges { node { id } } } }`, id)
301			body := gqlPost(t, srv, q)
302			if errs := gqlErrors(body); len(errs) > 0 {
303				t.Fatalf("GraphQL errors for %q: %v", q, errs)
304			}
305			var resp struct {
306				Data struct {
307					WorkersByProject struct {
308						TotalCount int `json:"totalCount"`
309						Edges      []struct {
310							Node struct {
311								ID string `json:"id"`
312							} `json:"node"`
313						} `json:"edges"`
314					} `json:"workersByProject"`
315				} `json:"data"`
316			}
317			if err := json.Unmarshal(body, &resp); err != nil {
318				t.Fatalf("invalid JSON for %q: %v", q, err)
319			}
320			ids := make([]string, len(resp.Data.WorkersByProject.Edges))
321			for i, e := range resp.Data.WorkersByProject.Edges {
322				ids[i] = e.Node.ID
323			}
324			if resp.Data.WorkersByProject.TotalCount != len(ids) {
325				t.Fatalf("totalCount %d != edges %d", resp.Data.WorkersByProject.TotalCount, len(ids))
326			}
327			return ids
328		}
329	
330		if got := workersForProject(projA.ID); len(got) != 1 || got[0] != "wk-scope-A" {
331			t.Errorf("workersByProject(%q) = %v, want [wk-scope-A]", projA.ID, got)
332		}
333		if got := workersForProject(projB.ID); len(got) != 1 || got[0] != "wk-scope-B" {
334			t.Errorf("workersByProject(%q) = %v, want [wk-scope-B]", projB.ID, got)
335		}
336	
337		// Unknown project id → empty list, no error.
338		if got := workersForProject("proj-does-not-exist"); len(got) != 0 {
339			t.Errorf("workersByProject(unknown) = %v, want []", got)
340		}
341	
342		// Global workers query returns both workers.
343		if total := queryTotal(`{ workers { totalCount edges { node { id } } } }`); total != 2 {
344			t.Errorf("workers (global) totalCount = %d, want 2", total)
345		}
346	}
